mapper.select:
SELECT n.id, n.user_id, n.collection_item_id, n.title, n.note_type, n.content, n.is_public, n.create_time, n.update_time, n.description, n.cover_image, n.finshed_at, n.status, ci.title AS collectionItemTitle, ci.source_url AS sourceUrl FROM note n LEFT JOIN collection_item ci ON n.collection_item_id = ci.id AND ci.deleted = 0 WHERE n.user_id = #{userId} AND n.deleted = 0
AND n.note_type = #{noteType}
AND n.status = #{status}
AND (n.title LIKE CONCAT('%', #{keyword}, '%') OR n.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY n.update_time DESC
